import React from 'react';

// Parses text like "漢字《かんじ》" into <ruby>漢字<rt>かんじ</rt></ruby> elements
export const parseRuby = (text: string) => {
  if (!text) return null;
  const regex = /([\u4e00-\u9faf\u3005-\u3007]+)《(.+?)》/g;
  const parts = [];
  let lastIndex = 0;
  let match;

  while ((match = regex.exec(text)) !== null) {
    // Push preceding text
    if (match.index > lastIndex) {
      parts.push(text.substring(lastIndex, match.index));
    }
    // Push ruby element
    parts.push(
      <ruby key={match.index}>
        {match[1]}
        <rt>{match[2]}</rt>
      </ruby>
    );
    lastIndex = regex.lastIndex;
  }
  // Push remaining text
  if (lastIndex < text.length) {
    parts.push(text.substring(lastIndex));
  }
  return <>{parts}</>;
};

// Strips ruby information "漢字《かんじ》" -> "漢字"
export const stripRuby = (text: string) => {
  if (!text) return "";
  return text.replace(/([\u4e00-\u9faf\u3005-\u3007]+)《.+?》/g, '$1');
};

import React from 'react';
import { parseRuby } from '../utils';

interface HeaderProps {
    title: string;
    mode?: 'quiz' | 'moshimo' | 'theme' | 'menu' | 'profile' | 'kimochi' | 'yesno';
}

const Header: React.FC<HeaderProps> = ({ title, mode = 'menu' }) => {
  const getColorClass = () => {
    switch (mode) {
      case 'quiz':
        return 'text-rose-500';
      case 'moshimo':
        return 'text-amber-500';
      case 'theme':
        return 'text-orange-500';
      case 'profile':
        return 'text-sky-500';
      case 'kimochi':
        return 'text-emerald-500';
      case 'yesno':
        return 'text-violet-500';
      default:
        return 'text-stone-800';
    }
  };

  return (
    <header className="text-center py-6 md:py-8">
      <h1 className={`text-4xl md:text-6xl font-extrabold transition-colors duration-300 ${getColorClass()}`}>
        {parseRuby(title)}
      </h1>
    </header>
  );
};

export default Header;

